18	Full Superellipse Corner Approximation (s ≥ 0)	Full Superellipse Corner Approximation (s ≥ 0)	Mathematics	High School	📚	\r\n<div class="container">\r\n    <h1>Full Superellipse Corner Approximation (s ≥ 0)</h1>\r\n    <p>Adjust the 's' value (superellipse value, log₂(k)) to see how the two symmetrical cubic Bezier curves approximate different convex corner shapes.</p>\r\n    \r\n    <label for="sValue">Superellipse 's' Value (k = 2^s):</label>\r\n    <input type="range" id="sValue" min="0" max="8" step="0.01" value="1">\r\n    <span id="sDisplay">s = 1.00</span>\r\n    <p class="k-text">Corresponding k: <span id="kDisplay"></span></p>\r\n    \r\n    <canvas id="superellipseCanvas" width="500" height="500"></canvas>\r\n    \r\n    <div class="legend">\r\n        <h2>Bezier Points Visualization (Scaled)</h2>\r\n        <p><span class="point-start-end">●</span> P0 (Start Point: (0, 1)) and P2 (End Point: (1, 0))</p>\r\n        <p><span class="point-diagonal">●</span> P1 (Diagonal Half-Corner: (0.5¹ᐟᵏ, 0.5¹ᐟᵏ))</p>\r\n        <p><span class="point-control1">●</span> C1 (Curve 1 Control 1: (a, 1)) and C4 (Curve 2 Control 2: (1, a))</p>\r\n        <p><span class="point-control2">●</span> C2 (Curve 1 Control 2) and C3 (Curve 2 Control 1) (These are symmetrical control points diagonal to P1)</p>\r\n        <p class="formula-text">Current a: <span id="aDisplay"></span> | Current b: <span id="bDisplay"></span></p>\r\n    </div>\r\n</div>\r\n\r\n\r\n<script>\r\n    // Constants computed using symbolic regression\r\nconst P = {\r\n    p0: 1.2430920942724248,\r\n    p1: 2.010479023614843,\r\n    p2: 0.32922901179443753,\r\n    p3: 0.2823023142212073, \r\n    p4: 1.3473704261055421,\r\n    p5: 2.9149468637949814,\r\n    p6: 0.9106507102917086\r\n};\r\n\r\n// Canvas and control setup\r\nconst canvas = document.getElementById('superellipseCanvas');\r\nconst ctx = canvas.getContext('2d');\r\nconst sSlider = document.getElementById('sValue');\r\nconst sDisplay = document.getElementById('sDisplay');\r\nconst kDisplay = document.getElementById('kDisplay');\r\nconst aDisplay = document.getElementById('aDisplay');\r\nconst bDisplay = document.getElementById('bDisplay');\r\n\r\nconst SCALE = 400; // Scaling factor for visualization\r\nconst OFFSET = 50; // Canvas padding\r\n\r\n/**\r\n * Calculates the 'k', 'a', and 'b' parameters, and the seven Bezier curve points \r\n * (P0, C1, C2, P1, C3, C4, P2) for a full convex superellipse corner.\r\n * @param {number} s The superellipse s value (log2(k)). Must be s >= 0 (k >= 1).\r\n * @returns {object} The calculated Bezier points and the values a, b, and k.\r\n */\r\nfunction calculateBezierPoints(s) {\r\n    // Ensure s >= 0 (k >= 1 for convex shapes)\r\n    if (s < 0) s = 0; \r\n    \r\n    // Calculate k: k = 2^s\r\n    const k = Math.pow(2, s);\r\n\r\n    // Destructure constants\r\n    const { p0, p1, p2, p3, p4, p5, p6 } = P;\r\n\r\n    // 1. Compute intermediate values based on s\r\n    const slope = p0 + (p6 - p0) * 0.5 * (1 + Math.tanh(p5 * (s - p1)));\r\n    const base = 1 / (1 + Math.exp(slope * p1));\r\n    const logistic = 1 / (1 + Math.exp(slope * (p1 - s)));\r\n\r\n    // 2. Compute a and b\r\n    const a = (logistic - base) / (1 - base);\r\n    const b = p2 * Math.exp(-p3 * Math.pow(s, p4)); \r\n\r\n    // 3. Compute end point coordinate (0.5^(1/k))\r\n    const X_end = Math.pow(0.5, 1/k);\r\n    const Y_end = X_end; // P1 is the diagonal point\r\n\r\n    // 4. Define the seven unique points\r\n    const points = {\r\n        // Curve 1 (P0 to P1)\r\n        P0: { x: 0, y: 1 },                 \r\n        C1: { x: a, y: 1 },                 \r\n        C2: { x: X_end - b, y: Y_end + b }, \r\n        P1: { x: X_end, y: Y_end },         \r\n        \r\n        // Curve 2 (P1 to P2) - Symmetrical reflection of Curve 1 points\r\n        C3: { x: Y_end + b, y: X_end - b }, // Reflected C2 (x, y swapped)\r\n        C4: { x: 1, y: a },                 // Reflected C1 (x, y swapped)\r\n        P2: { x: 1, y: 0 }                  // Reflected P0 (x, y swapped)\r\n    };\r\n    \r\n    return { points, a, b, k };\r\n}\r\n\r\n/**\r\n * Draws the two-segment Bezier curve and its control points on the canvas.\r\n * @param {object} params The parameters object containing points, a, b, and k.\r\n */\r\nfunction drawCurve({ points, a, b, k }) {\r\n    ctx.clearRect(0, 0, canvas.width, canvas.height);\r\n    \r\n    // --- Utility function to translate unit points (0 to 1) to canvas coordinates ---\r\n    const toCanvas = (p) => ({\r\n        // X: scale right (x increases)\r\n        x: p.x * SCALE + OFFSET,\r\n        // Y: scale down (y increases downwards). Invert Y to draw P0=(0,1) at the top.\r\n        y: (1 - p.y) * SCALE + OFFSET \r\n    });\r\n\r\n    const P0_c = toCanvas(points.P0);\r\n    const C1_c = toCanvas(points.C1);\r\n    const C2_c = toCanvas(points.C2);\r\n    const P1_c = toCanvas(points.P1);\r\n    const C3_c = toCanvas(points.C3);\r\n    const C4_c = toCanvas(points.C4);\r\n    const P2_c = toCanvas(points.P2);\r\n\r\n    // Update displays for k, a and b\r\n    kDisplay.textContent = k.toFixed(2);\r\n    aDisplay.textContent = a.toFixed(6);\r\n    bDisplay.textContent = b.toFixed(6);\r\n\r\n    // 1. Draw the Bezier Curve (Two Segments)\r\n    ctx.beginPath();\r\n    // Segment 1: P0 -> C1 -> C2 -> P1\r\n    ctx.moveTo(P0_c.x, P0_c.y);\r\n    ctx.bezierCurveTo(C1_c.x, C1_c.y, C2_c.x, C2_c.y, P1_c.x, P1_c.y);\r\n    // Segment 2: P1 -> C3 -> C4 -> P2\r\n    ctx.bezierCurveTo(C3_c.x, C3_c.y, C4_c.x, C4_c.y, P2_c.x, P2_c.y);\r\n    ctx.strokeStyle = 'black';\r\n    ctx.lineWidth = 4;\r\n    ctx.stroke();\r\n\r\n    // 2. Draw Control Lines (Cubic Bezier cages)\r\n    ctx.strokeStyle = '#ccc';\r\n    ctx.lineWidth = 1;\r\n    ctx.beginPath();\r\n    // Control cage for curve 1\r\n    ctx.moveTo(P0_c.x, P0_c.y);\r\n    ctx.lineTo(C1_c.x, C1_c.y);\r\n    ctx.lineTo(C2_c.x, C2_c.y);\r\n    ctx.lineTo(P1_c.x, P1_c.y);\r\n    // Control cage for curve 2\r\n    ctx.lineTo(C3_c.x, C3_c.y);\r\n    ctx.lineTo(C4_c.x, C4_c.y);\r\n    ctx.lineTo(P2_c.x, P2_c.y);\r\n    ctx.stroke();\r\n\r\n    // 3. Draw Points\r\n    const drawPoint = (p, color) => {\r\n        ctx.fillStyle = color;\r\n        ctx.beginPath();\r\n        ctx.arc(p.x, p.y, 5, 0, 2 * Math.PI);\r\n        ctx.fill();\r\n    };\r\n\r\n    drawPoint(P0_c, '#007bff'); // P0 (Start)\r\n    drawPoint(P2_c, '#007bff'); // P2 (End)\r\n    drawPoint(P1_c, '#28a745'); // P1 (Diagonal)\r\n    drawPoint(C1_c, '#ffc107'); // C1 \r\n    drawPoint(C4_c, '#ffc107'); // C4 (Symmetrical to C1)\r\n    drawPoint(C2_c, '#dc3545'); // C2\r\n    drawPoint(C3_c, '#dc3545'); // C3 (Symmetrical to C2)\r\n\r\n    // 4. Draw coordinate axes for reference (1x1 unit space)\r\n    ctx.strokeStyle = '#888';\r\n    ctx.lineWidth = 0.5;\r\n    ctx.setLineDash([2, 2]);\r\n    \r\n    // Y=1 axis (top of the unit square)\r\n    ctx.beginPath();\r\n    ctx.moveTo(OFFSET, OFFSET);\r\n    ctx.lineTo(OFFSET + SCALE, OFFSET);\r\n    ctx.stroke();\r\n    \r\n    // X=0 axis (left of the unit square)\r\n    ctx.beginPath();\r\n    ctx.moveTo(OFFSET, OFFSET);\r\n    ctx.lineTo(OFFSET, OFFSET + SCALE);\r\n    ctx.stroke();\r\n    \r\n    ctx.setLineDash([]);\r\n}\r\n\r\nfunction updateVisualization() {\r\n    const s = parseFloat(sSlider.value);\r\n    sDisplay.textContent = `s = ${s.toFixed(2)}`;\r\n    \r\n    const calculationResult = calculateBezierPoints(s);\r\n    drawCurve(calculationResult);\r\n}\r\n\r\n// Initial draw and event listener\r\nsSlider.addEventListener('input', updateVisualization);\r\nupdateVisualization();\r\n</script>\r\n\r\n<style>\r\n    body {\r\n    font-family: sans-serif;\r\n    background-color: #f0f0f0;\r\n    padding: 20px;\r\n}\r\n\r\n.container {\r\n    max-width: 550px;\r\n    margin: 0 auto;\r\n    background: #fff;\r\n    padding: 20px;\r\n    border-radius: 8px;\r\n    box-shadow: 0 4px 6px rgba(0,0,0,0.1);\r\n}\r\n\r\n#superellipseCanvas {\r\n    display: block;\r\n    border: 1px solid #ccc;\r\n    margin-top: 15px;\r\n}\r\n\r\n#kValue {\r\n    width: 100%;\r\n    margin: 10px 0;\r\n}\r\n\r\n.legend {\r\n    margin-top: 20px;\r\n    padding-top: 10px;\r\n    border-top: 1px dashed #ccc;\r\n}\r\n\r\n.point-p0 { color: #007bff; } /* Blue */\r\n.point-p1 { color: #28a745; } /* Green */\r\n.point-c1 { color: #ffc107; } /* Yellow */\r\n.point-c2 { color: #dc3545; } /* Red */\r\n\r\n.legend span {\r\n    font-size: 1.5em;\r\n    line-height: 0;\r\n    vertical-align: middle;\r\n    margin-right: 5px;\r\n}\r\n</style>			15	Beginner	default-lesson.png	\N	0	11	0.00	\N	t	2026-02-28 11:07:52.132879	2026-02-28 11:07:52.132879
